// OrderProcessingServiceImpl.java
package com.ecommerce.service;

import com.ecommerce.exception.OrderFault;
import com.ecommerce.exception.OrderProcessingException;
import com.ecommerce.model.*;

import javax.jws.WebService;
import javax.xml.ws.BindingType;
import javax.xml.ws.soap.SOAPBinding;
import java.math.BigDecimal;
import java.math.RoundingMode;
import java.text.SimpleDateFormat;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;
import java.util.logging.Level;
import java.util.logging.Logger;

@WebService(
        endpointInterface = "com.ecommerce.service.OrderProcessingService",
        serviceName = "OrderProcessingWebService",
        portName = "OrderProcessingPort",
        targetNamespace = "http://ecommerce.com/order"
)
@BindingType(SOAPBinding.SOAP12HTTP_BINDING)
public class OrderProcessingServiceImpl implements OrderProcessingService {

    private static final Logger LOGGER = Logger.getLogger(OrderProcessingServiceImpl.class.getName());

    private static final double TAX_RATE = 0.08;
    private static final double SHIPPING_BASE_COST = 9.99;
    private static final double FREE_SHIPPING_THRESHOLD = 500.0;
    private static final double BULK_DISCOUNT_THRESHOLD = 1000.0;
    private static final double BULK_DISCOUNT_RATE = 0.05;
    private static final double B2B_DISCOUNT_RATE = 0.10;

    private final Map<String, OrderRecord> orderStore = new ConcurrentHashMap<>();
    private final AtomicLong confirmationCounter = new AtomicLong(100000);

    private static class OrderRecord {
        String orderId;
        String customerId;
        String status;
        double totalPrice;
        Date lastUpdated;
        OrderRequest originalRequest;

        OrderRecord(String orderId, String customerId, String status, double totalPrice, OrderRequest request) {
            this.orderId = orderId;
            this.customerId = customerId;
            this.status = status;
            this.totalPrice = totalPrice;
            this.lastUpdated = new Date();
            this.originalRequest = request;
        }
    }

    @Override
    public OrderResponse processOrder(OrderRequest orderRequest) throws OrderProcessingException {
        LOGGER.info("Processing order: " + orderRequest.getOrderId() + " for customer: " + orderRequest.getCustomerId());

        validateOrderRequest(orderRequest);

        OrderResponse response = new OrderResponse();
        response.setOrderId(orderRequest.getOrderId());

        try {
            List<OrderItem> items = orderRequest.getItems();
            int totalItems = 0;
            double subtotal = 0.0;
            List<ItemDetail> itemDetails = new ArrayList<>();

            for (OrderItem item : items) {
                validateOrderItem(item);

                double itemSubtotal = roundToTwoDecimals(item.getUnitPrice() * item.getQuantity());
                subtotal += itemSubtotal;
                totalItems += item.getQuantity();

                String availability = checkAvailability(item);

                ItemDetail detail = new ItemDetail(
                        item.getItemId(),
                        item.getItemName(),
                        item.getQuantity(),
                        item.getUnitPrice(),
                        itemSubtotal,
                        availability
                );
                itemDetails.add(detail);

                LOGGER.info("Item: " + item.getItemName() + " | Qty: " + item.getQuantity() +
                        " | Unit: $" + item.getUnitPrice() + " | Subtotal: $" + itemSubtotal);
            }

            subtotal = roundToTwoDecimals(subtotal);

            double b2bDiscount = roundToTwoDecimals(subtotal * B2B_DISCOUNT_RATE);
            double bulkDiscount = 0.0;
            if (subtotal >= BULK_DISCOUNT_THRESHOLD) {
                bulkDiscount = roundToTwoDecimals(subtotal * BULK_DISCOUNT_RATE);
            }
            double totalDiscount = roundToTwoDecimals(b2bDiscount + bulkDiscount);

            double discountedSubtotal = roundToTwoDecimals(subtotal - totalDiscount);

            double taxAmount = roundToTwoDecimals(discountedSubtotal * TAX_RATE);

            double shippingCost = subtotal >= FREE_SHIPPING_THRESHOLD ? 0.0 : SHIPPING_BASE_COST;

            double totalPrice = roundToTwoDecimals(discountedSubtotal + taxAmount + shippingCost);

            boolean allAvailable = itemDetails.stream()
                    .allMatch(d -> "IN_STOCK".equals(d.getAvailabilityStatus()));

            String confirmationNumber = "B2B-CONF-" + confirmationCounter.incrementAndGet();

            String estimatedDelivery = calculateEstimatedDelivery(allAvailable);

            response.setSubtotal(subtotal);
            response.setDiscountAmount(totalDiscount);
            response.setTaxAmount(taxAmount);
            response.setShippingCost(shippingCost);
            response.setTotalPrice(totalPrice);
            response.setTotalItems(totalItems);
            response.setItemDetails(itemDetails);
            response.setConfirmationNumber(confirmationNumber);
            response.setEstimatedDelivery(estimatedDelivery);

            if (allAvailable) {
                response.setStatus("CONFIRMED");
                response.setMessage("Order processed successfully. All items are in stock.");
            } else {
                response.setStatus("PARTIALLY_CONFIRMED");
                response.setMessage("Order processed. Some items have limited availability. Please check item details.");
            }

            if (!validatePaymentMethod(orderRequest.getPaymentMethod())) {
                response.setStatus("PAYMENT_PENDING");
                response.setMessage("Order received but payment method '" + orderRequest.getPaymentMethod() + "' requires verification.");
            }

            OrderRecord record = new OrderRecord(
                    orderRequest.getOrderId(),
                    orderRequest.getCustomerId(),
                    response.getStatus(),
                    totalPrice,
                    orderRequest
            );
            orderStore.put(orderRequest.getOrderId(), record);

            LOGGER.info("Order " + orderRequest.getOrderId() + " processed. Total: $" + totalPrice +
                    " | Status: " + response.getStatus() + " | Confirmation: " + confirmationNumber);

        } catch (OrderProcessingException e) {
            throw e;
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Unexpected error processing order: " + orderRequest.getOrderId(), e);
            throw new OrderProcessingException(
                    "Internal error processing order",
                    new OrderFault("ERR_INTERNAL", "An unexpected error occurred: " + e.getMessage()),
                    e
            );
        }

        return response;
    }

    @Override
    public OrderStatusResponse getOrderStatus(OrderStatusRequest statusRequest) throws OrderProcessingException {
        LOGGER.info("Checking status for order: " + statusRequest.getOrderId());

        if (statusRequest.getOrderId() == null || statusRequest.getOrderId().trim().isEmpty()) {
            throw new OrderProcessingException(
                    "Order ID is required",
                    new OrderFault("ERR_MISSING_ORDER_ID", "Order ID must be provided")
            );
        }

        OrderRecord record = orderStore.get(statusRequest.getOrderId());

        OrderStatusResponse response = new OrderStatusResponse();
        response.setOrderId(statusRequest.getOrderId());

        if (record != null) {
            if (!record.customerId.equals(statusRequest.getCustomerId())) {
                throw new OrderProcessingException(
                        "Customer ID does not match",
                        new OrderFault("ERR_AUTH", "Customer ID does not match the order record")
                );
            }
            response.setStatus(record.status);
            response.setMessage("Order found in system.");
            response.setTotalPrice(record.totalPrice);
            SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss");
            response.setLastUpdated(sdf.format(record.lastUpdated));
        } else {
            response.setStatus("NOT_FOUND");
            response.setMessage("Order not found in the system.");
            response.setTotalPrice(0.0);
            response.setLastUpdated("");
        }

        return response;
    }

    @Override
    public OrderResponse cancelOrder(String orderId, String customerId) throws OrderProcessingException {
        LOGGER.info("Cancellation request for order: " + orderId);

        if (orderId == null || orderId.trim().isEmpty()) {
            throw new OrderProcessingException(
                    "Order ID is required for cancellation",
                    new OrderFault("ERR_MISSING_ORDER_ID", "Order ID must be provided")
            );
        }

        OrderRecord record = orderStore.get(orderId);

        OrderResponse response = new OrderResponse();
        response.setOrderId(orderId);

        if (record == null) {
            throw new OrderProcessingException(
                    "Order not found",
                    new OrderFault("ERR_ORDER_NOT_FOUND", "Order " + orderId + " does not exist")
            );
        }

        if (!record.customerId.equals(customerId)) {
            throw new OrderProcessingException(
                    "Unauthorized cancellation attempt",
                    new OrderFault("ERR_AUTH", "Customer ID does not match the order record")
            );
        }

        if ("CANCELLED".equals(record.status)) {
            throw new OrderProcessingException(
                    "Order already cancelled",
                    new OrderFault("ERR_ALREADY_CANCELLED", "Order " + orderId + " is already cancelled")
            );
        }

        if ("SHIPPED".equals(record.status) || "DELIVERED".equals(record.status)) {
            throw new OrderProcessingException(
                    "Cannot cancel order",
                    new OrderFault("ERR_CANNOT_CANCEL", "Order " + orderId + " has already been " + record.status.toLowerCase())
            );
        }

        record.status = "CANCELLED";
        record.lastUpdated = new Date();

        response.setStatus("CANCELLED");
        response.setMessage("Order " + orderId + " has been successfully cancelled.");
        response.setTotalPrice(0.0);
        response.setSubtotal(0.0);
        response.setTaxAmount(0.0);
        response.setShippingCost(0.0);
        response.setDiscountAmount(0.0);
        response.setTotalItems(0);
        response.setConfirmationNumber("CANCEL-" + System.currentTimeMillis());
        response.setEstimatedDelivery("N/A");

        LOGGER.info("Order " + orderId + " cancelled successfully.");

        return response;
    }

    @Override
    public OrderResponse calculateOrderTotal(OrderRequest orderRequest) throws OrderProcessingException {
        LOGGER.info("Calculating total for order: " + orderRequest.getOrderId());

        validateOrderRequest(orderRequest);

        OrderResponse response = new OrderResponse();
        response.setOrderId(orderRequest.getOrderId());

        List<OrderItem> items = orderRequest.getItems();
        int totalItems = 0;
        double subtotal = 0.0;
        List<ItemDetail> itemDetails = new ArrayList<>();

        for (OrderItem item : items) {
            validateOrderItem(item);

            double itemSubtotal = roundToTwoDecimals(item.getUnitPrice() * item.getQuantity());
            subtotal += itemSubtotal;
            totalItems += item.getQuantity();

            ItemDetail detail = new ItemDetail(
                    item.getItemId(),
                    item.getItemName(),
                    item.getQuantity(),
                    item.getUnitPrice(),
                    itemSubtotal,
                    "N/A"
            );
            itemDetails.add(detail);
        }

        subtotal = roundToTwoDecimals(subtotal);
        double b2bDiscount = roundToTwoDecimals(subtotal * B2B_DISCOUNT_RATE);
        double bulkDiscount = subtotal >= BULK_DISCOUNT_THRESHOLD ?
                roundToTwoDecimals(subtotal * BULK_DISCOUNT_RATE) : 0.0;
        double totalDiscount = roundToTwoDecimals(b2bDiscount + bulkDiscount);
        double discountedSubtotal = roundToTwoDecimals(subtotal - totalDiscount);
        double taxAmount = roundToTwoDecimals(discountedSubtotal * TAX_RATE);
        double shippingCost = subtotal >= FREE_SHIPPING_THRESHOLD ? 0.0 : SHIPPING_BASE_COST;
        double totalPrice = roundToTwoDecimals(discountedSubtotal + taxAmount + shippingCost);

        response.setSubtotal(subtotal);
        response.setDiscountAmount(totalDiscount);
        response.setTaxAmount(taxAmount);
        response.setShippingCost(shippingCost);
        response.setTotalPrice(totalPrice);
        response.setTotalItems(totalItems);
        response.setItemDetails(itemDetails);
        response.setStatus("QUOTE");
        response.setMessage("Price calculation complete. This is a quote, not a confirmed order.");
        response.setConfirmationNumber("QUOTE-" + System.currentTimeMillis());
        response.setEstimatedDelivery("TBD");

        return response;
    }

    private void validateOrderRequest(OrderRequest request) throws OrderProcessingException {
        if (request == null) {
            throw new OrderProcessingException(
                    "Order request is null",
                    new OrderFault("ERR_NULL_REQUEST", "Order request cannot be null")
            );
        }

        if (request.getOrderId() == null || request.getOrderId().trim().isEmpty()) {
            throw new OrderProcessingException(
                    "Order ID is required",
                    new OrderFault("ERR_MISSING_ORDER_ID", "Order ID must be provided")
            );
        }

        if (request.getCustomerId() == null || request.getCustomerId().trim().isEmpty()) {
            throw new OrderProcessingException(
                    "Customer ID is required",
                    new OrderFault("ERR_MISSING_CUSTOMER_ID", "Customer ID must be provided")
            );
        }

        if (request.getItems() == null || request.getItems().isEmpty()) {
            throw new OrderProcessingException(
                    "Order must contain at least one item",
                    new OrderFault("ERR_EMPTY_ORDER", "At least one order item is required")
            );
        }

        if (request.getShippingAddress() == null || request.getShippingAddress().trim().isEmpty()) {
            throw new OrderProcessingException(
                    "Shipping address is required",
                    new OrderFault("ERR_MISSING_ADDRESS", "Shipping address must be provided")
            );
        }
    }

    private void validateOrderItem(OrderItem item) throws OrderProcessingException {
        if (item.getItemId() == null || item.getItemId().trim().isEmpty()) {
            throw new OrderProcessingException(
                    "Item ID is required",
                    new OrderFault("ERR_MISSING_ITEM_ID", "Each item must have an ID")
            );
        }

        if (item.getQuantity() <= 0) {
            throw new OrderProcessingException(
                    "Invalid quantity for item: " + item.getItemId(),
                    new OrderFault("ERR_INVALID_QUANTITY", "Quantity must be greater than zero for item " + item.getItemId())
            );
        }

        if (item.getUnitPrice() < 0) {
            throw new OrderProcessingException(
                    "Invalid price for item: " + item.getItemId(),
                    new OrderFault("ERR_INVALID_PRICE", "Price cannot be negative for item " + item.getItemId())
            );
        }

        if (item.getQuantity() > 10000) {
            throw new OrderProcessingException(
                    "Quantity exceeds maximum for item: " + item.getItemId(),
                    new OrderFault("ERR_MAX_QUANTITY", "Maximum quantity per item is 10000")
            );
        }
    }

    private String checkAvailability(OrderItem item) {
        if (item.getQuantity() > 500) {
            return "BACKORDER";
        } else if (item.getQuantity() > 100) {
            return "LIMITED_STOCK";
        }
        return "IN_STOCK";
    }

    private boolean validatePaymentMethod(String paymentMethod) {
        if (paymentMethod == null) return false;
        Set<String> validMethods = new HashSet<>(Arrays.asList(
                "PURCHASE_ORDER", "NET_30", "NET_60", "WIRE_TRANSFER",
                "CREDIT_CARD", "ACH", "INVOICE"
        ));
        return validMethods.contains(paymentMethod.toUpperCase());
    }

    private String calculateEstimatedDelivery(boolean allInStock) {
        Calendar cal = Calendar.getInstance();
        if (allInStock) {
            cal.add(Calendar.DAY_OF_MONTH, 5);
        } else {
            cal.add(Calendar.DAY_OF_MONTH, 14);
        }
        SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd");
        return sdf.format(cal.getTime());
    }

    private double roundToTwoDecimals(double value) {
        return BigDecimal.valueOf(value).setScale(2, RoundingMode.HALF_UP).doubleValue();
    }
}

// SOAPMessageHandler.java
package com.ecommerce.handler;

import javax.xml.namespace.QName;
import javax.xml.soap.SOAPMessage;
import javax.xml.ws.handler.MessageContext;
import javax.xml.ws.handler.soap.SOAPHandler;
import javax.xml.ws.handler.soap.SOAPMessageContext;
import java.io.ByteArrayOutputStream;
import java.util.Collections;
import java.util.Set;
import java.util.logging.Level;
import java.util.logging.Logger;

public class SOAPMessageHandler implements SOAPHandler<SOAPMessageContext> {

    private static final Logger LOGGER = Logger.getLogger(SOAPMessageHandler.class.getName());

    @Override
    public Set<QName> getHeaders() {
        return Collections.emptySet();
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean isOutbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);
        SOAPMessage message = context.getMessage();

        try {
            ByteArrayOutputStream baos = new ByteArrayOutputStream();
            message.writeTo(baos);
            String soapXml = baos.toString("UTF-8");

            if (isOutbound) {
                LOGGER.info("Outbound SOAP Response:\n" + soapXml);
            } else {
                LOGGER.info("Inbound SOAP Request:\n" + soapXml);
            }
        } catch (Exception e) {
            LOGGER.log(Level.WARNING, "Error logging SOAP message", e);
        }

        return true;
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        SOAPMessage message = context.getMessage();
        try {
            ByteArrayOutputStream baos = new ByteArrayOutputStream();
            message.writeTo(baos);
            LOGGER.severe("SOAP Fault:\n" + baos.toString("UTF-8"));
        } catch (Exception e) {
            LOGGER.log(Level.WARNING, "Error logging SOAP fault", e);
        }
        return true;
    }

    @Override
    public void close(MessageContext context) {
    }
}

// HandlerResolver.java
package com.ecommerce.handler;

import javax.xml.ws.handler.Handler;
import javax.xml.ws.handler.HandlerResolver;
import javax.xml.ws.handler.PortInfo;
import java.util.ArrayList;
import java.util.List;

public class OrderHandlerResolver implements HandlerResolver {

    @Override
    @SuppressWarnings("rawtypes")
    public List<Handler> getHandlerChain(PortInfo portInfo) {
        List<Handler> handlers = new ArrayList<>();
        handlers.add(new SOAPMessageHandler());
        return handlers;
    }
}

// OrderServicePublisher.java
package com.ecommerce;

import com.ecommerce.service.OrderProcessingServiceImpl;

import javax.xml.ws.Endpoint;
import java.util.logging.Logger;

public class OrderServicePublisher {

    private static final Logger LOGGER = Logger.getLogger(OrderServicePublisher.class.getName());
    private static final String SERVICE_URL = "http://localhost:8080/b2b/orderservice";

    public static void main(String[] args) {
        try {
            OrderProcessingServiceImpl service = new OrderProcessingServiceImpl();
            Endpoint endpoint = Endpoint.publish(SERVICE_URL, service);

            LOGGER.info("B2B Order Processing SOAP Web Service is running.");
            LOGGER.info("Service URL: " + SERVICE_URL);
            LOGGER.info("WSDL URL: " + SERVICE_URL + "?wsdl");
            LOGGER.info("Press Ctrl+C to stop the service.");

            Runtime.getRuntime().addShutdownHook(new Thread(() -> {
                LOGGER.info("Shutting down B2B Order Processing Service...");
                endpoint.stop();
                LOGGER.info("Service stopped.");
            }));

        } catch (Exception e) {
            LOGGER.severe("Failed to start service: " + e.getMessage());
            e.printStackTrace();
        }
    }
}

// OrderServiceClient.java
package com.ecommerce.client;

import com.ecommerce.model.OrderItem;
import com.ecommerce.model.OrderRequest;
import com.ecommerce.model.OrderResponse;
import com.ecommerce.model.OrderStatusRequest;
import com.ecommerce.model.OrderStatusResponse;
import com.ecommerce.model.ItemDetail;
import com.ecommerce.service.OrderProcessingService;

import javax.xml.namespace.QName;
import javax.xml.ws.Service;
import java.net.URL;
import java.util.ArrayList;
import java.util.List;
import java.util.logging.Logger;

public class OrderServiceClient {

    private static final Logger LOGGER = Logger.getLogger(OrderServiceClient.class.getName());

    public static void main(String[] args) {
        try {
            URL wsdlUrl = new URL("http://localhost:8080/b2b/orderservice?wsdl");
            QName serviceName = new QName("http://ecommerce.com/order", "OrderProcessingWebService");

            Service service = Service.create(wsdlUrl, serviceName);
            OrderProcessingService orderService = service.getPort(OrderProcessingService.class);

            // Test 1: Process a B2B order
            LOGGER.info("=== Test 1: Processing B2B Order ===");
            OrderRequest orderRequest = createSampleOrder();
            OrderResponse response = orderService.processOrder(orderRequest);
            printOrderResponse(response);

            // Test 2: Calculate order total (quote)
            LOGGER.info("\n=== Test 2: Calculate Order Total (Quote) ===");
            OrderResponse quoteResponse = orderService.calculateOrderTotal(orderRequest);
            printOrderResponse(quoteResponse);

            // Test 3: Check order status
            LOGGER.info("\n=== Test 3: Check Order Status ===");
            OrderStatusRequest statusRequest = new OrderStatusRequest();
            statusRequest.setOrderId("B2B-ORD-2024-001");
            statusRequest.setCustomerId("CUST-B2B-100");
            OrderStatusResponse statusResponse = orderService.getOrderStatus(statusRequest);
            printStatusResponse(statusResponse);

            // Test 4: Cancel order
            LOGGER.info("\n=== Test 4: Cancel Order ===");
            OrderResponse cancelResponse = orderService.cancelOrder("B2B-ORD-2024-001", "CUST-B2B-100");
            printOrderResponse(cancelResponse);

            // Test 5: Verify cancellation
            LOGGER.info("\n=== Test 5: Verify Cancellation ===");
            OrderStatusResponse cancelStatus = orderService.getOrderStatus(statusRequest);
            printStatusResponse(cancelStatus);

        } catch (Exception e) {
            LOGGER.severe("Client error: " + e.getMessage());
            e.printStackTrace();
        }
    }

    private static OrderRequest createSampleOrder() {
        OrderRequest request = new OrderRequest();
        request.setOrderId("B2B-ORD-2024-001");
        request.setCustomerId("CUST-B2B-100");
        request.setCustomerName("Acme Corporation");
        request.setShippingAddress("123 Industrial Blvd, Suite 500, Chicago, IL 60601");
        request.setPaymentMethod("NET_30");

        List<OrderItem> items = new ArrayList<>();

        OrderItem item1 = new OrderItem();
        item1.setItemId("SKU-WIDGET-001");
        item1.setItemName("Industrial Widget Type A");
        item1.setUnitPrice(24.99);
        item1.setQuantity(50);
        items.add(item1);

        OrderItem item2 = new OrderItem();
        item2.setItemId("SKU-GADGET-002");
        item2.setItemName("Premium Gadget Model B");
        item2.setUnitPrice(149.95);
        item2.setQuantity(20);
        items.add(item2);

        OrderItem item3 = new OrderItem();
        item3.setItemId("SKU-SUPPLY-003");
        item3.setItemName("Bulk Supply Pack C");
        item3.setUnitPrice(8.50);
        item3.setQuantity(200);
        items.add(item3);

        OrderItem item4 = new OrderItem();
        item4.setItemId("SKU-TOOL-004");
        item4.setItemName("Precision Tool Set D");
        item4.setUnitPrice(299.99);
        item4.setQuantity(5);
        items.add(item4);

        request.setItems(items);
        return request;
    }

    private static void printOrderResponse(OrderResponse response) {
        LOGGER.info("Order ID: " + response.getOrderId());
        LOGGER.info("Status: " + response.getStatus());
        LOGGER.info("Message: " + response.getMessage());
        LOGGER.info("Total Items: " + response.getTotalItems());
        LOGGER.info("Subtotal: $" + response.getSubtotal());
        LOGGER.info("Discount: -$" + response.getDiscountAmount());
        LOGGER.info("Tax: $" + response.getTaxAmount());
        LOGGER.info("Shipping: $" + response.getShippingCost());
        LOGGER.info("Total Price: $" + response.getTotalPrice());
        LOGGER.info("Confirmation: " + response.getConfirmationNumber());
        LOGGER.info("Est. Delivery: " + response.getEstimatedDelivery());

        if (response.getItemDetails() != null) {
            LOGGER.info("--- Item Details ---");
            for (ItemDetail detail : response.getItemDetails()) {
                LOGGER.info("  " + detail.getItemName() + " | Qty: " + detail.getQuantity() +
                        " | $" + detail.getUnitPrice() + " each | Subtotal: $" + detail.getSubtotal() +
                        " | " + detail.getAvailabilityStatus());
            }
        }
    }

    private static void printStatusResponse(OrderStatusResponse response) {
        LOGGER.info("Order ID: " + response.getOrderId());
        LOGGER.info("Status: " + response.getStatus());
        LOGGER.info("Message: " + response.getMessage());
        LOGGER.info("Total Price: $" + response.getTotalPrice());
        LOGGER.info("Last Updated: " + response.getLastUpdated());
    }
}